from decimal import Decimal, ROUND_HALF_UP


class Money:
    """Money arithmetic that avoids floating-point errors."""

    def __init__(self, amount):
        # Store as Decimal to avoid IEEE-754 rounding issues
        self.amount = Decimal(str(amount))

    def add(self, other):
        return Money(self.amount + other.amount)

    def multiply(self, factor):
        return Money(self.amount * Decimal(str(factor)))

    def equals(self, other, precision=2):
        """Compare with rounding to given decimal places."""
        quant = Decimal('0.' + '0' * precision)
        return (self.amount.quantize(quant, rounding=ROUND_HALF_UP) ==
                other.amount.quantize(quant, rounding=ROUND_HALF_UP))

    def to_cents(self):
        """Convert to integer cents."""
        return int((self.amount * 100).quantize(Decimal('1'), rounding=ROUND_HALF_UP))

    def format(self):
        return f"${self.amount:.2f}"

    def __repr__(self):
        return f"Money({self.amount})"

